contract MultiSigWallet {



    uint constant public MAX_OWNER_COUNT = 50;



    event Confirmation(address indexed sender, uint indexed transactionId);

    event Revocation(address indexed sender, uint indexed transactionId);

    event Submission(uint indexed transactionId);

    event Execution(uint indexed transactionId);

    event ExecutionFailure(uint indexed transactionId);

    event Deposit(address indexed sender, uint value);

    event OwnerAddition(address indexed owner);

    event OwnerRemoval(address indexed owner);

    event RequirementChange(uint required);



    mapping (uint => Transaction) public transactions;

    mapping (uint => mapping (address => bool)) public confirmations;

    mapping (address => bool) public isOwner;

    address[] public owners;

    uint public required;

    uint public transactionCount;



    struct Transaction {

        address destination;

        uint value;

        bytes data;

        bool executed;

    }



    modifier onlyWallet() {

        if (msg.sender != address(this))

            revert();

        _;

    }



    modifier ownerDoesNotExist(address owner) {

        if (isOwner[owner])

            revert();

        _;

    }



    modifier ownerExists(address owner) {

        if (!isOwner[owner])

            revert();

        _;

    }



    modifier transactionExists(uint transactionId) {

        if (transactions[transactionId].destination == 0)

            revert();

        _;

    }



    modifier confirmed(uint transactionId, address owner) {

        if (!confirmations[transactionId][owner])

            revert();

        _;

    }



    modifier notConfirmed(uint transactionId, address owner) {

        if (confirmations[transactionId][owner])

            revert();

        _;

    }



    modifier notExecuted(uint transactionId) {

        if (transactions[transactionId].executed)

            revert();

        _;

    }



    modifier notNull(address _address) {

        if (_address == 0)

            revert();

        _;

    }



    modifier validRequirement(uint ownerCount, uint _required) {

        if (   ownerCount > MAX_OWNER_COUNT

            || _required > ownerCount

            || _required == 0

            || ownerCount == 0)

            revert();

        _;

    }





    function()

        payable

    {

        if (msg.value > 0)

            Deposit(msg.sender, msg.value);

    }











    function MultiSigWallet(address[] _owners, uint _required)

        public

        validRequirement(_owners.length, _required)

    {

        for (uint i=0; i<_owners.length; i++) {

            if (isOwner[_owners[i]] || _owners[i] == 0)

                revert();

            isOwner[_owners[i]] = true;

        }

        owners = _owners;

        required = _required;

    }







    function addOwner(address owner)

        public

        onlyWallet

        ownerDoesNotExist(owner)

        notNull(owner)

        validRequirement(owners.length + 1, required)

    {

        isOwner[owner] = true;

        owners.push(owner);

        OwnerAddition(owner);

    }







    function removeOwner(address owner)

        public

        onlyWallet

        ownerExists(owner)

    {

        isOwner[owner] = false;

        for (uint i=0; i<owners.length - 1; i++)

            if (owners[i] == owner) {

                owners[i] = owners[owners.length - 1];

                break;

            }

        owners.length -= 1;

        if (required > owners.length)

            changeRequirement(owners.length);

        OwnerRemoval(owner);

    }









    function replaceOwner(address owner, address newOwner)

        public

        onlyWallet

        ownerExists(owner)

        ownerDoesNotExist(newOwner)

    {

        for (uint i=0; i<owners.length; i++)

            if (owners[i] == owner) {

                owners[i] = newOwner;

                break;

            }

        isOwner[owner] = false;

        isOwner[newOwner] = true;

        OwnerRemoval(owner);

        OwnerAddition(newOwner);

    }







    function changeRequirement(uint _required)

        public

        onlyWallet

        validRequirement(owners.length, _required)

    {

        required = _required;

        RequirementChange(_required);

    }













    function submitTransaction(address destination, uint value, bytes data)

        public

        returns (uint transactionId)

    {

        transactionId = addTransaction(destination, value, data);

        confirmTransaction(transactionId);

    }







    function confirmTransaction(uint transactionId)

        public

        ownerExists(msg.sender)

        transactionExists(transactionId)

        notConfirmed(transactionId, msg.sender)

    {

        confirmations[transactionId][msg.sender] = true;

        Confirmation(msg.sender, transactionId);

        executeTransaction(transactionId);

    }







    function revokeConfirmation(uint transactionId)

        public

        ownerExists(msg.sender)

        confirmed(transactionId, msg.sender)

        notExecuted(transactionId)

    {

        confirmations[transactionId][msg.sender] = false;

        Revocation(msg.sender, transactionId);

    }







    function executeTransaction(uint transactionId)

        public

        ownerExists(msg.sender)

        confirmed(transactionId, msg.sender)

        notExecuted(transactionId)

    {

        if (isConfirmed(transactionId)) {

            Transaction storage txn = transactions[transactionId];

            txn.executed = true;

            if (txn.destination.call.value(txn.value)(txn.data))

                Execution(transactionId);

            else {

                ExecutionFailure(transactionId);

                txn.executed = false;

            }

        }

    }









    function isConfirmed(uint transactionId)

        public

        constant

        returns (bool)

    {

        uint count = 0;

        for (uint i=0; i<owners.length; i++) {

            if (confirmations[transactionId][owners[i]])

                count += 1;

            if (count == required)

                return true;

        }

    }















    function addTransaction(address destination, uint value, bytes data)

        internal

        notNull(destination)

        returns (uint transactionId)

    {

        transactionId = transactionCount;

        transactions[transactionId] = Transaction({

            destination: destination,

            value: value,

            data: data,

            executed: false

        });

        transactionCount += 1;

        Submission(transactionId);

    }











    function getConfirmationCount(uint transactionId)

        public

        constant

        returns (uint count)

    {

        for (uint i=0; i<owners.length; i++)

            if (confirmations[transactionId][owners[i]])

                count += 1;

    }











    function getTransactionCount(bool pending, bool executed)

        public

        constant

        returns (uint count)

    {

        for (uint i=0; i<transactionCount; i++)

            if (   pending && !transactions[i].executed

                || executed && transactions[i].executed)

                count += 1;

    }







    function getOwners()

        public

        constant

        returns (address[])

    {

        return owners;

    }









    function getConfirmations(uint transactionId)

        public

        constant

        returns (address[] _confirmations)

    {

        address[] memory confirmationsTemp = new address[](owners.length);

        uint count = 0;

        uint i;

        for (i=0; i<owners.length; i++)

            if (confirmations[transactionId][owners[i]]) {

                confirmationsTemp[count] = owners[i];

                count += 1;

            }

        _confirmations = new address[](count);

        for (i=0; i<count; i++)

            _confirmations[i] = confirmationsTemp[i];

    }















    function getTransactionIds(uint from, uint to, bool pending, bool executed)

        public

        constant

        returns (uint[] _transactionIds)

    {

        uint[] memory transactionIdsTemp = new uint[](transactionCount);

        uint count = 0;

        uint i;

        for (i=0; i<transactionCount; i++)

            if (   pending && !transactions[i].executed

                || executed && transactions[i].executed)

            {

                transactionIdsTemp[count] = i;

                count += 1;

            }

        _transactionIds = new uint[](to - from);

        for (i=from; i<to; i++)

            _transactionIds[i - from] = transactionIdsTemp[i];

    }

}

contract GigaGivingToken is StandardToken {

    using SafeMath for uint256;



    uint256 private fundingGoal = 0 ether;

    uint256 private amountRaised;



    uint256 private constant PHASE_1_PRICE = 1600000000000;

    uint256 private constant PHASE_2_PRICE = 2000000000000; 

    uint256 private constant PHASE_3_PRICE = 2500000000000; 

    uint256 private constant PHASE_4_PRICE = 4000000000000;

    uint256 private constant PHASE_5_PRICE = 5000000000000; 

    uint256 private constant DURATION = 30 minutes;  



    uint256 public constant TOTAL_TOKENS = 15000000;

    uint256 public constant  CROWDSALE_TOKENS = 12000000;  





    uint256 public startTime;

    uint256 public tokenSupply;



    address public creator;

    address public beneficiary;



    string public name = "JTEST";

    string public symbol = "JT";

    string public version = "JT.0";

    uint256 public decimals = 0;  





    mapping(address => uint256) public ethBalanceOf;

    bool public fundingGoalReached = false;

    bool public crowdsaleClosed = false;   

    bool public refundsOpen = false;   



    function GigaGivingToken (address icoBeneficiary) public {

        creator = msg.sender;

        beneficiary = icoBeneficiary;

        totalSupply = TOTAL_TOKENS;         



        balances[beneficiary] = TOTAL_TOKENS.sub(CROWDSALE_TOKENS);

        Transfer(0x0, icoBeneficiary, TOTAL_TOKENS.sub(CROWDSALE_TOKENS));



        balances[this] = CROWDSALE_TOKENS;

        Transfer(0x0, this, CROWDSALE_TOKENS);              

        tokenSupply = CROWDSALE_TOKENS;



        startTime = 1510527600;

    }   



    function approveAndCall(address _spender, uint256 _value, bytes _extraData) public returns (bool success) {

        allowed[msg.sender][_spender] = _value;

        Approval(msg.sender, _spender, _value);

        require(_spender.call(bytes4(bytes32(sha3("receiveApproval(address,uint256,address,bytes)"))), msg.sender, _value, this, _extraData));

        return true;

    } 



    function () public payable {

        require(now >= startTime);

        require(now <= startTime + DURATION);

        require(!crowdsaleClosed);

        require(msg.value > 0);

        uint256 amount = msg.value;

        uint256 coinTotal = 0;      



        if (now > startTime + 20 minutes) {

            coinTotal = amount.div(PHASE_5_PRICE);

        } else if (now > startTime + 15 minutes) {

            coinTotal = amount.div(PHASE_4_PRICE);

        } else if (now > startTime + 10 minutes) {

            coinTotal = amount.div(PHASE_3_PRICE);

        } else if (now > startTime + 5 minutes) {

            coinTotal = amount.div(PHASE_2_PRICE);

        } else {

            coinTotal = amount.div(PHASE_1_PRICE);

        }



        ethBalanceOf[msg.sender] = ethBalanceOf[msg.sender].add(amount);              

        balances[msg.sender] = balances[msg.sender].add(coinTotal);

        balances[this] = balances[this].sub(coinTotal);

        amountRaised = amountRaised.add(amount);

        tokenSupply = tokenSupply.sub(coinTotal);

        transfer(msg.sender, coinTotal);

    }  



    modifier afterDeadline() { 

        if (now >= (startTime + DURATION)) {

            _;

        }

    }



    function checkGoalReached() public afterDeadline {

        if (amountRaised >= fundingGoal) {

            fundingGoalReached = true;

        }

        crowdsaleClosed = true;

    }



    function safeWithdrawal() public afterDeadline {

        if (refundsOpen) {

            uint amount = ethBalanceOf[msg.sender];

            ethBalanceOf[msg.sender] = 0;

            if (amount > 0) {

                if (!msg.sender.send(amount)) {

                    ethBalanceOf[msg.sender] = amount;

                }

            }

        }



        if (fundingGoalReached && beneficiary == msg.sender) {

            if (beneficiary.send(amountRaised)) {

                this.transfer(msg.sender, tokenSupply);

            } else {               

                fundingGoalReached = false;

            }

        }

    }



    function enableRefunds() public afterDeadline {

        require(msg.sender == beneficiary);

        refundsOpen = true;

    }

}

