contract OwnedUpgradeabilityProxy is UpgradeabilityProxy {





  event ProxyOwnershipTransferred(address previousOwner, address newOwner);


  bytes32 private constant proxyOwnerPosition = keccak256("EtherAuthority.io.proxy.owner");




  constructor () public {
    setUpgradeabilityOwner(msg.sender);
  }




  modifier onlyProxyOwner() {
    require(msg.sender == proxyOwner());
    _;
  }





  function proxyOwner() public view returns (address owner) {
    bytes32 position = proxyOwnerPosition;
    assembly {
      owner := sload(position)
    }
  }




  function setUpgradeabilityOwner(address newProxyOwner) internal {
    bytes32 position = proxyOwnerPosition;
    assembly {
      sstore(position, newProxyOwner)
    }
  }





  function transferProxyOwnership(address newOwner) public onlyProxyOwner {
    require(newOwner != address(0));
    emit ProxyOwnershipTransferred(proxyOwner(), newOwner);
    setUpgradeabilityOwner(newOwner);
  }





  function upgradeTo(address implementation) public onlyProxyOwner {
    _upgradeTo(implementation);
  }








  function upgradeToAndCall(address implementation, bytes memory data) payable public onlyProxyOwner {
    _upgradeTo(implementation);
    (bool success,) = address(this).call.value(msg.value).gas(200000)(data);
    require(success,'initialize function errored');
  }

  function generateData() public view returns(bytes memory){

    return abi.encodeWithSignature("initialize(address)",msg.sender);

  }
}

contract MultiBuyer is MultiChanger {
    using CheckedERC20 for ERC20;

    function buy(
        IMultiToken _mtkn,
        uint256 _minimumReturn,
        bytes _callDatas,
        uint[] _starts 
    )
        public
        payable
    {
        change(_callDatas, _starts);

        uint mtknTotalSupply = _mtkn.totalSupply(); 
        uint256 bestAmount = uint256(-1);
        for (uint i = _mtkn.tokensCount(); i > 0; i--) {
            ERC20 token = _mtkn.tokens(i - 1);
            if (token.allowance(this, _mtkn) == 0) {
                token.asmApprove(_mtkn, uint256(-1));
            }

            uint256 amount = mtknTotalSupply.mul(token.balanceOf(this)).div(token.balanceOf(_mtkn));
            if (amount < bestAmount) {
                bestAmount = amount;
            }
        }

        require(bestAmount >= _minimumReturn, "buy: return value is too low");
        _mtkn.bundle(msg.sender, bestAmount);
        if (address(this).balance > 0) {
            msg.sender.transfer(address(this).balance);
        }
        for (i = _mtkn.tokensCount(); i > 0; i--) {
            token = _mtkn.tokens(i - 1);
            if (token.balanceOf(this) > 0) {
                token.asmTransfer(msg.sender, token.balanceOf(this));
            }
        }
    }

    function buyFirstTokens(
        IMultiToken _mtkn,
        bytes _callDatas,
        uint[] _starts 
    )
        public
        payable
    {
        change(_callDatas, _starts);

        uint tokensCount = _mtkn.tokensCount();
        uint256[] memory amounts = new uint256[](tokensCount);
        for (uint i = 0; i < tokensCount; i++) {
            ERC20 token = _mtkn.tokens(i);
            amounts[i] = token.balanceOf(this);
            if (token.allowance(this, _mtkn) == 0) {
                token.asmApprove(_mtkn, uint256(-1));
            }
        }

        _mtkn.bundleFirstTokens(msg.sender, msg.value.mul(1000), amounts);
        if (address(this).balance > 0) {
            msg.sender.transfer(address(this).balance);
        }
        for (i = _mtkn.tokensCount(); i > 0; i--) {
            token = _mtkn.tokens(i - 1);
            if (token.balanceOf(this) > 0) {
                token.asmTransfer(msg.sender, token.balanceOf(this));
            }
        }
    }



    function buyOnApprove(
        IMultiToken _mtkn,
        uint256 _minimumReturn,
        ERC20 _throughToken,
        address[] _exchanges,
        bytes _datas,
        uint[] _datasIndexes, 
        uint256[] _values
    )
        public
        payable
    {
        require(_datasIndexes.length == _exchanges.length + 1, "buy: _datasIndexes should start with 0 and end with LENGTH");
        require(_values.length == _exchanges.length, "buy: _values should have the same length as _exchanges");

        for (uint i = 0; i < _exchanges.length; i++) {
            bytes memory data = new bytes(_datasIndexes[i + 1] - _datasIndexes[i]);
            for (uint j = _datasIndexes[i]; j < _datasIndexes[i + 1]; j++) {
                data[j - _datasIndexes[i]] = _datas[j];
            }

            if (_throughToken != address(0) && _values[i] == 0) {
                if (_throughToken.allowance(this, _exchanges[i]) == 0) {
                    _throughToken.asmApprove(_exchanges[i], uint256(-1));
                }
                require(_exchanges[i].call(data), "buy: exchange arbitrary call failed");
            } else {
                require(_exchanges[i].call.value(_values[i])(data), "buy: exchange arbitrary call failed");
            }
        }

        j = _mtkn.totalSupply(); 
        uint256 bestAmount = uint256(-1);
        for (i = _mtkn.tokensCount(); i > 0; i--) {
            ERC20 token = _mtkn.tokens(i - 1);
            if (token.allowance(this, _mtkn) == 0) {
                token.asmApprove(_mtkn, uint256(-1));
            }

            uint256 amount = j.mul(token.balanceOf(this)).div(token.balanceOf(_mtkn));
            if (amount < bestAmount) {
                bestAmount = amount;
            }
        }

        require(bestAmount >= _minimumReturn, "buy: return value is too low");
        _mtkn.bundle(msg.sender, bestAmount);
        if (address(this).balance > 0) {
            msg.sender.transfer(address(this).balance);
        }
        if (_throughToken != address(0) && _throughToken.balanceOf(this) > 0) {
            _throughToken.asmTransfer(msg.sender, _throughToken.balanceOf(this));
        }
    }
}

contract KeyRewardPool is DSStop , DSMath{



    DSToken public key;

    uint public rewardStartTime;



    uint constant public yearlyRewardPercentage = 10; 

    uint public totalRewardThisYear;

    uint public collectedTokens;

    address public withdrawer;



    event TokensWithdrawn(address indexed _holder, uint _amount);

    event LogSetWithdrawer(address indexed _withdrawer);



    modifier onlyWithdrawer {

        require(msg.sender == withdrawer);

        _;

    }



    function KeyRewardPool(uint _rewardStartTime, address _key, address _withdrawer){

        require(_rewardStartTime != 0 );

        require(_key != address(0) );

        require(_withdrawer != address(0) );



        rewardStartTime = _rewardStartTime;

        key = DSToken(_key);

        withdrawer = _withdrawer;

    }





    function collectToken() stoppable onlyWithdrawer{

        uint _time = time();

        var _key = key;  



        require(_time > rewardStartTime);



        uint balance = _key.balanceOf(address(this));

        uint total = add(collectedTokens, balance);



        uint remainingTokens = total;



        uint yearCount = yearFor(_time);



        for(uint i = 0; i < yearCount; i++) {

            remainingTokens =  div( mul(remainingTokens, 100 - yearlyRewardPercentage), 100);

        }



        totalRewardThisYear =  div( mul(remainingTokens, yearlyRewardPercentage), 100);





        uint canExtractThisYear = div( mul(totalRewardThisYear, (_time - rewardStartTime)  % 365 days), 365 days);



        uint canExtract = canExtractThisYear + total - remainingTokens;



        canExtract = sub(canExtract, collectedTokens);



        if(canExtract > balance) {

            canExtract = balance;

        }





        collectedTokens = add(collectedTokens, canExtract);



        assert(_key.transfer(withdrawer, canExtract)); 

        TokensWithdrawn(withdrawer, canExtract);

    }





    function yearFor(uint timestamp) constant returns(uint) {

        return timestamp < rewardStartTime

            ? 0

            : sub(timestamp, rewardStartTime) / (365 days);

    }





    function time() constant returns (uint) {

        return now;

    }



    function setWithdrawer(address _withdrawer) auth {

        withdrawer = _withdrawer;

        LogSetWithdrawer(_withdrawer);

    }













    function transferTokens(address dst, uint wad, address _token) public auth note {

        require( _token != address(key));

        if (wad > 0) {

            ERC20 token = ERC20(_token);

            token.transfer(dst, wad);

        }

    }





}

